
'use client';

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { MapPin, Share2 } from "lucide-react";
import { MapComponent } from "@/components/map";
import { useState, useEffect } from "react";

export default function LiveLocationPage() {
  const [currentPosition, setCurrentPosition] = useState<{lat: number, lng: number} | null>(null);

  useEffect(() => {
    // Simulate getting driver's location
    if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
            (position) => {
                setCurrentPosition({
                    lat: position.coords.latitude,
                    lng: position.coords.longitude,
                });
            },
            () => {
                // Fallback location
                setCurrentPosition({ lat: 34.0522, lng: -118.2437 });
            }
        );
    } else {
        // Fallback for browsers that don't support geolocation
        setCurrentPosition({ lat: 34.0522, lng: -118.2437 });
    }
  }, []);

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold font-headline">Live Location</h1>
        <p className="text-muted-foreground">Share your real-time location with admins and parents.</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2"><MapPin className="h-5 w-5 text-primary" /> Current Location</CardTitle>
          <CardDescription>Your current location is being tracked on the map below.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
           <div className="aspect-video bg-muted rounded-lg">
             {currentPosition && (
                <MapComponent center={currentPosition} markers={[{...currentPosition, label: 'You'}]} zoom={15} />
             )}
           </div>
          <Button className="w-full" size="lg">
              <Share2 className="mr-2 h-4 w-4" /> Share Live Location
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}
