type MapComponentProps = {
    markers?: { lat: number; lng: number; label: string }[];
    path?: { lat: number; lng: number }[];
    center: { lat: number; lng: number };
    zoom?: number;
};

const MissingApiKeyMessage = () => (
    <div className="h-full w-full bg-muted/50 flex items-center justify-center rounded-lg p-4">
        <div className="flex flex-col items-center text-center gap-2">
            <AlertCircle className="h-8 w-8 text-destructive" />
            <p className="font-semibold text-destructive">Google Maps API Key is Missing</p>
            <p className="text-muted-foreground text-sm">To display the map, please add your Google Maps API key to the .env file as <code className="bg-muted px-1 py-0.5 rounded-sm">NEXT_PUBLIC_GOOGLE_MAPS_API_KEY</code>.</p>
        </div>
    </div>
);

export const MapComponent = ({ markers, path, center, zoom = 12 }: MapComponentProps) => {
    const apiKey = process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY;

    const { isLoaded, loadError } = useJsApiLoader({
        googleMapsApiKey: apiKey || '',
        preventGoogleFontsLoading: true,
    });

    if (!apiKey || apiKey === 'YOUR_API_KEY_HERE') {
        return <MissingApiKeyMessage />;
    }

    if (loadError) {
        return <div className="h-full w-full bg-destructive/20 flex items-center justify-center rounded-lg"><p className="text-destructive font-semibold">Error loading map</p></div>;
    }

    if (!isLoaded) {
        return <Skeleton className="h-full w-full" />;
    }

    return (
        <GoogleMap
            mapContainerStyle={containerStyle}
            center={center}
            zoom={zoom}
            options={mapOptions}
        >
            {markers && markers.map((marker, index) => (
                <MarkerF key={index} position={marker} label={{ text: marker.label, className: 'map-marker-label' }} />
            ))}
            {path && (
                <Polyline
                    path={path}
                    options={{
                        strokeColor: 'hsl(var(--primary))',
                        strokeOpacity: 0.8,
                        strokeWeight: 4,
                    }}
                />
            )}
        </GoogleMap>
    );
};
